export async function GET() {
  const admin = createAdminSupabase()
  const results: string[] = []

  // Get familia IDs
  const { data: familias } = await admin.from('familias').select('id,slug')
  const camionesId = familias?.find((f: any) => f.slug === 'camiones-articulados')?.id
  const excavId = familias?.find((f: any) => f.slug === 'excavadoras')?.id

  if (!camionesId || !excavId) {
    return NextResponse.json({ error: 'Familias not found', familias })
  }
  results.push(`Familias: camiones=${camionesId}, excavadoras=${excavId}`)

  // Delete existing models if any
  await admin.from('modelos').delete().in('codigo', ['A25J', 'EC230FL3'])
  results.push('Deleted existing models')

  // Insert A25J
  const { data: a25Model, error: e1 } = await admin.from('modelos').insert({
    familia_id: camionesId,
    codigo: 'A25J',
    nombre: 'Volvo A25J Articulated Hauler',
    descripcion: 'Camión Articulado de 25 toneladas. Motor D11 Stage III, capacidad de carga 23.5 ton.',
    precio_fob: 413055.0,
    precio_lista: 413055.0,
    activo: true
  }).select('id').single()
  if (e1) return NextResponse.json({ error: 'A25J model insert failed', detail: e1.message })
  results.push(`A25J model inserted: ${a25Model.id}`)

  // Insert A25J items in batches
  const a25Items = A25_ITEMS.map((it: any) => ({ ...it, modelo_id: a25Model.id, precio_lista: it.precio_fob }))
  for (let i = 0; i < a25Items.length; i += 50) {
    const { error } = await admin.from('items').insert(a25Items.slice(i, i+50))
    if (error) return NextResponse.json({ error: `A25J items batch ${i} failed`, detail: error.message })
  }
  results.push(`A25J: ${a25Items.length} items inserted`)

  // Insert EC230FL3
  const { data: ec230Model, error: e2 } = await admin.from('modelos').insert({
    familia_id: excavId,
    codigo: 'EC230FL3',
    nombre: 'Volvo EC230FL3 Crawler Excavator',
    descripcion: 'Excavadora de Cadenas 23 toneladas. Motor D6 Tier 3, cuchara GP estándar.',
    precio_fob: 159190.0,
    precio_lista: 159190.0,
    activo: true
  }).select('id').single()
  if (e2) return NextResponse.json({ error: 'EC230FL3 model insert failed', detail: e2.message })
  results.push(`EC230FL3 model inserted: ${ec230Model.id}`)

  // Insert EC230FL3 items in batches
  const ec230Items = EC230_ITEMS.map((it: any) => ({ ...it, modelo_id: ec230Model.id, precio_lista: it.precio_fob }))
  for (let i = 0; i < ec230Items.length; i += 50) {
    const { error } = await admin.from('items').insert(ec230Items.slice(i, i+50))
    if (error) return NextResponse.json({ error: `EC230FL3 items batch ${i} failed`, detail: error.message })
  }
  results.push(`EC230FL3: ${ec230Items.length} items inserted`)

  return NextResponse.json({ ok: true, results })
}
